window.htmx=window.htmx||{version:"local-minimal",process:function(){}};document.addEventListener("click",async function(e){var t=e.target.closest("[hx-get]");if(!t)return;e.preventDefault();var r=await fetch(t.getAttribute("hx-get"));var h=await r.text();var s=t.getAttribute("hx-target");if(s){var n=document.querySelector(s);if(n)n.innerHTML=h;}});
